mapper.update:
update t_fun_memory
begin_time = #{beginTime}, end_time = #{endTime}, fun_duration = #{funDuration}, fun_type = #{funType}, fun_app = #{funApp}, fun_consume = #{funConsume}, fun_content = #{funContent}, memory_place = #{memoryPlace}, memory_place_detail = #{memoryPlaceDetail}, memory_images = #{memoryImages}, memory_source = #{memorySource}, row_memory_no = #{rowMemoryNo}, memory_status = #{memoryStatus}, update_time = now(), update_by = #{updateBy}
where id = #{id}

mapper.select:
select t.id, t.memory_no, t.begin_time, t.end_time, t.fun_duration, t.fun_type, t.fun_app, t.fun_consume, t.fun_content, t.memory_place, t.memory_place_detail, t.memory_images, t.memory_source, t.memory_owner, t.row_memory_no, t.update_time, t.update_by, t.memory_status, i.name as memoryOwnerName from t_fun_memory t left join t_sys_person_info i on i.account_id = t.memory_owner
and t.memory_no like concat('%', #{memoryNo}, '%')
and t.fun_type in
#{item}
and t.fun_app in
#{item}
and t.begin_time >= #{beginTime}
and t.begin_time <= #{endTime}
and t.memory_source in
#{item}
and t.memory_owner = #{memoryOwner}
and t.memory_status in
#{item}
order by t.begin_time desc
